59	describe('getCards', () => {
60	  beforeEach(() => initDb(':memory:'));
61	  afterEach(() => closeDb());
62	
63	  it('returns empty array when no cards exist', () => {
64	    assert.deepEqual(getCards(), []);
65	  });
66	
67	  it('returns cards with empty comments array', () => {
68	    createCard({ title: 'T' });
69	    const result = getCards();
70	    assert.deepEqual(result[0].comments, []);
71	  });
72	
73	  it('returns cards ordered by column then position (alphabetical column order)', () => {
74	    createCard({ title: 'Done1', column: 'done' });
75	    createCard({ title: 'Done2', column: 'done' });
76	    createCard({ title: 'Ready1', column: 'ready' });
77	    const result = getCards();
78	    assert.equal(result[0].column, 'done');
79	    assert.equal(result[1].column, 'done');
80	    assert.equal(result[2].column, 'ready');
81	    assert.ok(result[0].position < result[1].position);
82	  });
83	
84	  it('nests comments under the correct card', () => {
85	    const cardA = createCard({ title: 'Card A' });
86	    const cardB = createCard({ title: 'Card B' });
87	    createComment(cardA.id, { author: 'Alice', content: 'Comment 1' });
88	    createComment(cardA.id, { author: 'Alice', content: 'Comment 2' });
89	    createComment(cardB.id, { author: 'Bob', content: 'Comment 3' });
90	    const cards = getCards();
91	    const foundA = cards.find(c => c.id === cardA.id);
92	    const foundB = cards.find(c => c.id === cardB.id);
93	    assert.equal(foundA.comments.length, 2);
