// BEFORE:
if (resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
  const app = createApp();
  const PORT = process.env.PORT || 3001;
  app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
}

// AFTER:
if (resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
  const app = createApp();
  const PORT = process.env.PORT || 3001;
  const server = app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
  initWs(server);
}
```

`app.listen()` returns the underlying `http.Server` instance. `initWs(server)` attaches the WebSocketServer to the HTTP server's `upgrade` event. The WebSocketServer does not require the HTTP server to already be listening; attaching immediately after `listen()` is the correct pattern.

